import React, { useState, useEffect, useCallback } from 'react';
import { Download, FileSpreadsheet, FileText } from 'lucide-react';
import { DataTable } from '../../components/ui/DataTable';
import { getSchemeWiseReport, exportSchemeWiseReport } from '../../services/reports.service';
import { getSchemes } from '../../services/master.service';
import { getDistricts } from '../../services/master.service';
import toast from 'react-hot-toast';
import DropdownSearch from '../../components/common/DropdownSearch';

const SchemeWiseReport = () => {
  const [reportData, setReportData] = useState([]);
  const [schemes, setSchemes] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [exportLoading, setExportLoading] = useState(false);
  const [filters, setFilters] = useState({
    district_id: '',
    scheme_id: ''
  });

  const fetchSchemes = useCallback(async () => {
    try {
      const response = await getSchemes({ is_active: true });
      setSchemes(response.data || []);
    } catch (err) {
      toast.error('Failed to load schemes');
    }
  }, []);

  const fetchDistricts = useCallback(async () => {
    try {
      const response = await getDistricts({ is_active: true });
      setDistricts(response.data || []);
    } catch (err) {
      toast.error('Failed to load districts');
    }
  }, []);

  const fetchReportData = useCallback(async () => {
    setLoading(true);
    try {
      const params = {
        ...filters,
        district_id: filters.district_id || undefined,
        scheme_id: filters.scheme_id || undefined
      };
      
      const response = await getSchemeWiseReport(params);
      setReportData(response.data || []);
    } catch (err) {
      toast.error(err.message || 'Failed to load report data');
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    fetchSchemes();
    fetchDistricts();
  }, [fetchSchemes, fetchDistricts]);

  useEffect(() => {
    fetchReportData();
  }, [fetchReportData]);

  const handleFilterChange = (field, value) => {
    setFilters(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleExport = async (format) => {
    setExportLoading(true);
    try {
      const params = {
        ...filters,
        district_id: filters.district_id || undefined,
        scheme_id: filters.scheme_id || undefined
      };
      
      await exportSchemeWiseReport(format, params);
      toast.success(`Report exported as ${format.toUpperCase()}`);
    } catch (err) {
      toast.error(err.message || 'Failed to export report');
    } finally {
      setExportLoading(false);
    }
  };

  const columns = [
    { key: 'scheme_name', header: 'Scheme Name' },
    { key: 'scheme_code', header: 'Scheme Code' },
    { key: 'district_name', header: 'District' },
    { key: 'total_employees', header: 'Total Employees' },
    { key: 'active_employees', header: 'Active Employees' },
    { key: 'inactive_employees', header: 'Inactive Employees' },
  ];

  const filteredSchemes = schemes.filter(scheme => 
    !filters.district_id || scheme.district_id === parseInt(filters.district_id)
  );

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Scheme-wise Report</h1>
        <p className="text-gray-600">View employee statistics by scheme</p>
      </div>

      {/* Filters */}
      <div className="bg-white p-4 rounded-lg shadow-sm mb-6">
        <div className="flex flex-wrap gap-4 items-end">
          <div className="min-w-[200px]">
            <label className="block text-sm font-medium text-gray-700 mb-1">
              District
            </label>
            <DropdownSearch
              value={filters.district_id}
              onChange={(e) => handleFilterChange('district_id', e.target.value)}
              options={districts.map(d => ({
                id: d.district_id,
                name: d.district_name
              }))}
              placeholder="All Districts"
            />
          </div>

          <div className="min-w-[200px]">
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Scheme
            </label>
            <DropdownSearch
              value={filters.scheme_id}
              onChange={(e) => handleFilterChange('scheme_id', e.target.value)}
              options={filteredSchemes.map(s => ({
                id: s.scheme_id,
                name: s.scheme_name
              }))}
              placeholder="All Schemes"
              disabled={!filters.district_id}
            />
          </div>

          <div className="flex gap-2 ml-auto">
            <button
              onClick={() => handleExport('excel')}
              disabled={exportLoading || loading}
              className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              <FileSpreadsheet className="h-4 w-4" />
              Export Excel
            </button>
            <button
              onClick={() => handleExport('pdf')}
              disabled={exportLoading || loading}
              className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              <FileText className="h-4 w-4" />
              Export PDF
            </button>
          </div>
        </div>
      </div>

      {/* Report Data */}
      <div className="bg-white rounded-lg shadow-sm">
        <DataTable
          data={reportData}
          columns={columns}
          loading={loading}
          pagination={false}
        />
      </div>

      {reportData.length === 0 && !loading && (
        <div className="text-center py-12 text-gray-500">
          <Download className="h-12 w-12 mx-auto mb-4 text-gray-300" />
          <p>No data found for the selected filters</p>
        </div>
      )}
    </div>
  );
};

export default SchemeWiseReport;
