import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import PostWiseReport from '../pages/reports/PostWiseReport';
import PostSelectedReport from '../pages/reports/PostSelectedReport';
import FinalListReport from '../pages/reports/FinalListReport';
import DistrictWiseReport from '../pages/reports/DistrictWiseReport';
import SchemeWiseReport from '../pages/reports/SchemeWiseReport';

const ReportRoutes = () => {
    return (
        <Routes>
            <Route path="/" element={<Navigate to="post-selected" replace />} />
            <Route path="post-selected" element={<PostSelectedReport />} />
            <Route path="final-list" element={<FinalListReport />} />
            <Route path="post-wise" element={<PostWiseReport />} />
            <Route path="district-wise" element={<DistrictWiseReport />} />
            <Route path="scheme-wise" element={<SchemeWiseReport />} />
        </Routes>
    );
};

export default ReportRoutes;
