import { useEffect, useState, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import { FileSpreadsheet, Download, FileText } from 'lucide-react';
import { Card } from '../../components/common/Card';
import { PageHeader } from '../../components/common/PageHeader';
import { Button } from '../../components/common/Button';
import DropdownSearch from '../../components/common/DropdownSearch';
import toast from 'react-hot-toast';
import api from '../../services/api';

const stages = [
  { value: 'ELIGIBLE', label: 'Eligible List' },
  { value: 'PROVISIONAL_SELECTED', label: 'Provisional List' },
  { value: 'SELECTED', label: 'Final List' }
];

const FinalListReport = () => {
  const [searchParams] = useSearchParams();

  const [posts, setPosts] = useState([]);
  const [districts, setDistricts] = useState([]);

  const [selectedPost, setSelectedPost] = useState(searchParams.get('post_id') || '');
  const [selectedDistrict, setSelectedDistrict] = useState(searchParams.get('district_id') || '');
  const [selectedStage, setSelectedStage] = useState('ELIGIBLE');

  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchPosts();
    fetchDistricts();
  }, []);

  useEffect(() => {
    if (selectedPost && selectedDistrict) {
      fetchReport();
    } else {
      setRows([]);
    }
  }, [selectedPost, selectedDistrict, selectedStage]);

  const fetchPosts = async () => {
    try {
      const res = await api.get('/admin/review/posts');
      if (res.data.success) {
       setPosts(res.data.data.rows || []);
      }
    } catch {
      toast.error('Failed to load posts');
    }
  };

  const fetchDistricts = async () => {
    try {
      const res = await api.get('/masters/districts');
      if (res.data.success) {
        setDistricts(res.data.data || []);
      }
    } catch {
      toast.error('Failed to load districts');
    }
  };

  const fetchReport = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.append('district_id', selectedDistrict);
      params.append('stage', selectedStage);

      const res = await api.get(
        `/admin/review/posts/${selectedPost}/stage-report?${params.toString()}`
      );

      if (res.data.success) {
        setRows(res.data.data?.rows || []);
      }
    } catch (error) {
      toast.error('Failed to fetch report');
    } finally {
      setLoading(false);
    }
  };

  const downloadReport = async (format) => {
    if (!selectedPost || !selectedDistrict) {
      return toast.error('Select post and district first');
    }

    setLoading(true);
    try {
      const params = new URLSearchParams({
        district_id: selectedDistrict,
        stage: selectedStage,
        format
      });

      const response = await api.get(
        `/admin/review/posts/${selectedPost}/stage-report?${params.toString()}`,
        { responseType: 'blob' }
      );

      const blob = new Blob([response.data]);
      const link = document.createElement('a');
      link.href = window.URL.createObjectURL(blob);
      link.download = `report.${format === 'pdf' ? 'pdf' : 'xlsx'}`;
      link.click();

      toast.success(`Downloading ${format.toUpperCase()} report`);
    } catch {
      toast.error('Download failed');
    } finally {
      setLoading(false);
    }
  };

  const columns = useMemo(() => [
    { key: 'sr_no', header: 'Sr No.' },
    { key: 'application_no', header: 'Application No.' },
    { key: 'applicant_name', header: 'Applicant Name' },
    { key: 'gender', header: 'Gender' },
    { key: 'district_name', header: 'District' },
    { key: 'post_code', header: 'Post Code' },
    { key: 'stage_status', header: 'Stage' },
    { key: 'entered_at', header: 'Entered At' },
    { key: 'entered_by', header: 'Entered By' },
    { key: 'current_status', header: 'Current Status' }
  ], []);

  return (
    <div className="space-y-6">

      <PageHeader
        title="Final Lists (Post-wise)"
        subtitle="Download Eligible / Provisional / Final lists"
      />

      {/* FILTER CARD */}
      <Card className="p-5 rounded-2xl shadow-lg border border-slate-200">
        <div className="flex items-center gap-2 mb-4">
          <FileText className="h-5 w-5 text-slate-500" />
          <p className="text-lg font-semibold text-slate-700">
            Select Filters to View Report
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">

          {/* POST */}
          <div>
            <label className="text-xs font-semibold text-slate-400 mb-2 block">
              Post *
            </label>
            <DropdownSearch
              value={selectedPost}
              onChange={(e) => setSelectedPost(e.target.value)}
              options={posts.map(p => ({
                id: p.post_id,
                name: `${p.post_name} (${p.post_code})`
              }))}
              placeholder="Select Post"
            />
          </div>

          {/* DISTRICT */}
          <div>
            <label className="text-xs font-semibold text-slate-400 mb-2 block">
              District *
            </label>
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => setSelectedDistrict(e.target.value)}
              options={[
                { id: 'ALL', name: 'All Districts' },
                ...districts.map(d => ({
                  id: d.district_id,
                  name: d.district_name
                }))
              ]}
              placeholder="Select District"
            />
          </div>

          {/* STAGE */}
          <div>
            <label className="text-xs font-semibold text-slate-400 mb-2 block">
              Stage
            </label>

            <div className="flex gap-2">
              {stages.map(stage => (
                <button
                  key={stage.value}
                  onClick={() => setSelectedStage(stage.value)}
                  className={`flex-1 px-3 py-2 rounded-xl text-xs font-semibold transition ${
                    selectedStage === stage.value
                      ? 'bg-blue-600 text-white'
                      : 'bg-slate-100 text-slate-600'
                  }`}
                >
                  {stage.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* DOWNLOAD BUTTONS */}
        <div className="mt-5 flex gap-2">
          <Button onClick={() => downloadReport('pdf')}>
            <Download className="w-4 h-4 mr-2" /> PDF
          </Button>

          <Button onClick={() => downloadReport('xlsx')}>
            <FileSpreadsheet className="w-4 h-4 mr-2" /> Excel
          </Button>
        </div>
      </Card>

      {/* TABLE */}
      <Card>
        <div className="overflow-x-auto">

          {loading ? (
            <div className="text-center py-12">
              <div className="animate-spin h-10 w-10 border-b-2 border-blue-600 mx-auto" />
              <p className="mt-3 text-gray-500">Loading...</p>
            </div>
          ) : rows.length === 0 ? (
            <div className="flex flex-col items-center py-16">
              <FileText className="w-10 h-10 text-gray-300 mb-3" />
              <p className="text-gray-500">Select filters to view report</p>
            </div>
          ) : (
            <table className="min-w-full border rounded-xl overflow-hidden">
              <thead className="bg-slate-900 text-white">
                <tr>
                  {columns.map(col => (
                    <th key={col.key} className="px-5 py-3 text-left text-xs">
                      {col.header}
                    </th>
                  ))}
                </tr>
              </thead>

              <tbody className="bg-white divide-y">
                {rows.map((row, index) => (
                  <tr key={index} className="hover:bg-slate-50">
                    {columns.map(col => (
                      <td key={col.key} className="px-5 py-3 text-sm">
                        {row[col.key] ?? '—'}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          )}

        </div>
      </Card>

    </div>
  );
};

export default FinalListReport;