import api from './api';

const getData = (response) => response.data.data || response.data;

export const getPostWiseReport = async (params = {}) => {
    const response = await api.get('/admin/reports/post-wise', { params });
    return getData(response);
};

export const getPostSelectedReport = async (params = {}) => {
    const response = await api.get('/admin/reports/post-selected', { params });
    return getData(response);
};

export const exportPostWiseReport = async (format, params = {}) => {
    const response = await api.get('/admin/reports/post-wise/export', {
        params: { ...params, format },
        responseType: 'blob'
    });
    return response;
};

export const exportPostSelectedReport = async (format, params = {}) => {
    const response = await api.get('/admin/reports/post-selected/export', {
        params: { ...params, format },
        responseType: 'blob'
    });
    return response;
};

export const getPostAllotmentUpload = async (postId) => {
    const response = await api.get(`/admin/reports/post-selected/${postId}/allotment-upload`);
    return getData(response);
};

export const uploadPostAllotmentUpload = async (postId, file) => {
    const formData = new FormData();
    formData.append('file', file);

    const response = await api.post(`/admin/reports/post-selected/${postId}/allotment-upload`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
    });
    return getData(response);
};

export const deletePostAllotmentUpload = async (postId) => {
    const response = await api.delete(`/admin/reports/post-selected/${postId}/allotment-upload`);
    return getData(response);
};

