// ==================== ALLOTMENT EMAIL DISTRIBUTION ====================

export const scheduleAllotmentEmail = async (postId, scheduledDate) => {
    const response = await api.post(`/admin/reports/post-selected/${postId}/schedule-email`, {
        scheduled_date: scheduledDate
    });
    return getData(response);
};

