import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { DataTable } from '../../components/ui/DataTable';
import { PageHeader } from '../../components/common/PageHeader';
import { Button } from '../../components/common/Button';
import { Download } from 'lucide-react';
import toast from 'react-hot-toast';
import { exportPostWiseReport, getPostWiseReport } from '../../services/reports.service';
import { downloadBlobResponse } from '../../utils/download.utils';

const PostWiseReport = () => {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [exporting, setExporting] = useState(false);


    const fetchReport = useCallback(async () => {
        setLoading(true);
        try {
            const data = await getPostWiseReport();
            const list = data?.rows || data || [];
            setRows(Array.isArray(list) ? list : []);
        } catch (error) {
            console.error('Failed to load post wise report', error);
            toast.error(error.message || 'Failed to load report');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchReport();
    }, [fetchReport]);

    const columns = useMemo(() => [
        { key: 'post_code', header: 'Post Code', sortable: true },
        { key: 'post_name', header: 'Post Name', sortable: true },
        {
            key: 'application_count',
            header: 'Applications',
            className: 'text-center',
            render: (value) => value ?? 0
        },
        {
            key: 'selected_count',
            header: 'Selected',
            className: 'text-center',
            render: (value) => value ?? 0
        }
    ], []);

    // local client-side search (DataTable only provides search string)
    const filteredRows = useMemo(() => {
        const q = (searchQuery || '').trim().toLowerCase();
        if (!q) return rows;
        return rows.filter(r => {
            const code = String(r.post_code || '').toLowerCase();
            const name = String(r.post_name || '').toLowerCase();
            return code.includes(q) || name.includes(q);
        });
    }, [rows, searchQuery]);

    return (
        <div className="space-y-6">
            <PageHeader
                title="Post Wise Report"
                description="Post code/name with total applications and selected count"
                extraActions={(
                    <>
                        {/* <Button
                            variant="outline"
                            size="sm"
                            isLoading={exporting}
                            leftIcon={<Download className="h-4 w-4" />}
                            onClick={async () => {
                                try {
                                    setExporting(true);
                                    const resp = await exportPostWiseReport('csv');
                                    downloadBlobResponse(resp, 'post_wise_report.csv');
                                } catch (e) {
                                    toast.error(e.message || 'Failed to download CSV');
                                } finally {
                                    setExporting(false);
                                }
                            }}
                        >
                            CSV 
                        </Button> */}
                        <Button
                            variant="outline"
                            size="sm"
                            isLoading={exporting}
                            leftIcon={<Download className="h-4 w-4" />}
                            onClick={async () => {
                                try {
                                    setExporting(true);
                                    const resp = await exportPostWiseReport('xlsx');
                                    downloadBlobResponse(resp, 'post_wise_report.xlsx');
                                } catch (e) {
                                    toast.error(e.message || 'Failed to download Excel');
                                } finally {
                                    setExporting(false);
                                }
                            }}
                        >
                            Excel
                        </Button>
                        <Button
                            variant="outline"
                             size="sm"
                            isLoading={exporting}
                            leftIcon={<Download className="h-4 w-4" />}
                            onClick={async () => {
                                try {
                                    setExporting(true);
                                    const resp = await exportPostWiseReport('pdf');
                                    downloadBlobResponse(resp, 'post_wise_report.pdf');
                                } catch (e) {
                                    toast.error(e.message || 'Failed to download PDF');
                                } finally {
                                    setExporting(false);
                                }
                            }}
                        >
                            PDF
                        </Button>
                    </>
                )}
            />

            <DataTable
                columns={columns}
                data={filteredRows}
                onSearch={setSearchQuery}
                isLoading={loading}
                rowKey="post_id"
                enableSelection={false}
                showRowNumbers
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default PostWiseReport;
